function confirmPunishMute(){if(!currentUid){showToast('Not authenticated');return}var sp=safeEl('punish-selected');var di=safeEl('punish-duration');if(!sp||!sp.dataset.user){showToast('Select a user first');return}var target=sp.dataset.user;if(!target||target===''){showToast('Select a user first');return}var secs=parseInt(di?di.value:0)||300;if(secs<1||isNaN(secs)){showToast('Enter valid duration');return}db.ref('uids/'+currentUid).once('value',function(snap){var d=snap.val();var role=d&&d.role?d.role:'';if(role!=='moderator'&&role!=='admin'){showToast('Not authorized');return}var until=Date.now()+(secs*1000);muteData[target]={until:until,by:userStorage.currentUser};saveMutes();showToast(target+' muted for '+secs+'s');closePunishPanel();sysMsg('🔇 '+target+' has been muted for '+secs+'s.','global-chat','')})}
function confirmPunishUnmute(){if(!currentUid){showToast('Not authenticated');return}var sp=safeEl('punish-selected');if(!sp||!sp.dataset.user){showToast('Select a user first');return}var target=sp.dataset.user;if(!target||target===''){showToast('Select a user first');return}db.ref('uids/'+currentUid).once('value',function(snap){var d=snap.val();var role=d&&d.role?d.role:'';if(role!=='moderator'&&role!=='admin'){showToast('Not authorized');return}delete muteData[target];saveMutes();showToast(target+' unmuted');closePunishPanel();sysMsg('🔊 '+target+' has been unmuted.','global-chat','')})}
function sysMsg(text,ch,annType){var msg=buildSysMsg(text,annType||'');msg.annType=annType||'';var channel=ch||'global-chat';if(!communityData.channels[channel])communityData.channels[channel]=[];communityData.channels[channel].push(msg);if(fbReady){db.ref('channels/'+channel).push(msg)}else{saveCommunityData()}if(communityState.currentChannel===channel){renderCommunityMessages();var c2=safeEl('community-messages');if(c2)c2.scrollTop=c2.scrollHeight}return msg}
function renderUpdates(){var list=safeEl('updates-list');if(!list)return;list.innerHTML='';if(!updatesData.length){list.innerHTML='<p style="color:#999;text-align:center">No updates yet.</p>';return}var sorted=updatesData.slice().sort(function(a,b){return b.id-a.id});sorted.forEach(function(u){var card=document.createElement('div');card.className='update-card'+(u.priority==='high'?' high-priority':'');var modHtml=isMod()?'<div style="margin-top:10px;display:flex;gap:8px"><button onclick="deleteUpdate('+u.id+')" class="card-del-btn">Delete</button></div>':'';card.innerHTML='<div class="update-card-header"><div><span class="update-version-badge">'+fmtVersion(u.version)+'</span><span class="update-title">'+u.title+'</span></div><span class="update-meta">'+renderTimestamp(u.timestamp)+(u.author?' · '+u.author:'')+'</span></div><div class="update-body">'+u.description+'</div>'+(u.image?'<img src="'+u.image+'" style="max-width:100%;border-radius:8px;margin-top:8px" alt="">':'')+modHtml;list.appendChild(card)})}
function deleteUpdate(id){if(!confirm('Delete this update?'))return;var idx=updatesData.findIndex(function(u){return u.id===id});if(idx>-1){updatesData.splice(idx,1);saveUpdates();renderUpdates()}}
function renderStatusCard(){var c=safeEl('status-card');if(!c)return;var gameColor=statusData.game==='online'?'#00ff00':statusData.game==='maintenance'?'#ffaa00':'#ff4444';var modeLabel=statusData.game==='online'?'Online':statusData.game==='maintenance'?'Maintenance':'Offline';var devColor=statusData.dev==='online'?'#00ff00':'#ff4444';var modHtml=isMod()?'<div class="status-mod-btns"><button onclick="quickSetGame(\'online\')" class="stat-btn online-btn">Game Online</button><button onclick="quickSetGame(\'offline\')" class="stat-btn offline-btn">Game Offline</button><button onclick="quickSetGame(\'maintenance\')" class="stat-btn maint-btn">Maintenance</button><button onclick="quickSetDev(\'online\')" class="stat-btn online-btn">Dev Online</button><button onclick="quickSetDev(\'offline\')" class="stat-btn offline-btn">Dev Offline</button><button onclick="openModModal(\'status\')" class="stat-btn" style="background:rgba(255,255,255,0.08);color:#ccc;border-color:rgba(255,255,255,0.2)">Full Edit</button></div>':'';c.innerHTML='<div class="status-row"><span class="status-label">Game Server</span><span class="status-pill" style="background:'+gameColor+'22;color:'+gameColor+';border:1px solid '+gameColor+'44">'+modeLabel+'</span></div><div class="status-row"><span class="status-label">Dev / Website</span><span class="status-pill" style="background:'+devColor+'22;color:'+devColor+';border:1px solid '+devColor+'44">'+(statusData.dev==='online'?'Online':'Offline')+'</span></div><div class="status-row"><span class="status-label">Version</span><span style="color:#ccc">'+fmtVersion(statusData.version)+'</span></div><div class="status-row"><span class="status-label">Last Updated</span><span style="color:#ccc;font-size:12px">'+renderTimestamp(statusData.timestamp)+'</span></div>'+(statusData.announcement?'<div class="status-announcement">'+statusData.announcement+'</div>':'')+(statusData.note?'<div class="status-note">'+statusData.note+'</div>':'')+modHtml;updateVersionDisplay()}
function quickSetGame(s){statusData.game=s;statusData.timestamp=Date.now();saveStatus();renderStatusCard();showToast('Game status: '+s)}
function quickSetDev(s){statusData.dev=s;statusData.timestamp=Date.now();saveStatus();renderStatusCard();showToast('Dev status: '+s)}
function renderFaqs(){var dl=safeEl('faq-dynamic-list');if(!dl)return;dl.innerHTML='';var sorted=faqData.slice().sort(function(a,b){return b.id-a.id});sorted.forEach(function(f){var el=document.createElement('div');el.className='update';var modHtml=isMod()?'<div style="display:flex;gap:8px;margin-top:8px"><button onclick="editFaq('+f.id+')" class="card-edit-btn">Edit</button><button onclick="deleteFaq('+f.id+')" class="card-del-btn">Delete</button></div>':'';el.innerHTML='<h3>'+f.question+'</h3><p>'+f.answer+'</p>'+modHtml;dl.appendChild(el)})}
function deleteFaq(id){if(!confirm('Delete this FAQ?'))return;var i=faqData.findIndex(function(f){return f.id===id});if(i>-1){faqData.splice(i,1);saveFaqs();renderFaqs()}}
function editFaq(id){var f=faqData.find(function(f){return f.id===id});if(!f)return;var q=prompt('Edit question:',f.question);if(q===null)return;var a=prompt('Edit answer:',f.answer);if(a===null)return;f.question=q.trim();f.answer=a.trim();saveFaqs();renderFaqs()}
function renderGiveaways(){var list=safeEl('giveaway-list');if(!list)return;list.innerHTML='';var now=Date.now();if(!giveawayData.length){list.innerHTML='<div class="giveaway-empty"><p>No active giveaways right now.</p><p style="color:#aaa;font-size:13px">Check back later or follow announcements.</p></div>';return}giveawayData.slice().sort(function(a,b){return b.id-a.id}).forEach(function(g){var isEnded=g.ended||(g.endsAt&&now>g.endsAt);var hasEntered=userStorage.currentUser&&g.participants&&g.participants.includes(userStorage.currentUser);var timeLeft='';if(!isEnded&&g.endsAt){var diff=Math.max(0,g.endsAt-now);var h=Math.floor(diff/3600000);var m=Math.floor((diff%3600000)/60000);var s=Math.floor((diff%60000)/1000);timeLeft=h+'h '+m+'m '+s+'s'}var card=document.createElement('div');card.className='giveaway-card'+(isEnded?' giveaway-ended':'');var statusBadge=isEnded?'<span class="gw-badge ended">Ended</span>':'<span class="gw-badge active">Active</span>';var winnerHtml=isEnded&&g.winner?'<div class="gw-winner">🏆 Winner: <strong>'+g.winner+'</strong></div>':'';var enterBtn='';if(!isEnded){if(!userStorage.currentUser){enterBtn='<button onclick="showToast(\'Login to enter giveaways\')" class="gw-enter-btn">Login to Enter</button>'}else if(hasEntered){enterBtn='<button class="gw-enter-btn gw-entered" disabled>✓ Entered</button>'}else{enterBtn='<button onclick="enterGiveaway('+g.id+')" class="gw-enter-btn">Enter Giveaway</button>'}}var modHtml=isMod()?'<div class="gw-mod-actions"><button onclick="endGiveaway('+g.id+')" class="card-del-btn">'+(isEnded?'Re-pick Winner':'End Now')+'</button><button onclick="deleteGiveaway('+g.id+')" class="card-del-btn" style="background:rgba(255,0,0,0.15)">Delete</button></div>':'';card.innerHTML='<div class="gw-header">'+statusBadge+'<span class="gw-title">'+g.title+'</span></div><div class="gw-reward">🎁 Reward: <strong>'+g.reward+'</strong></div><p class="gw-desc">'+g.description+'</p>'+(timeLeft?'<div class="gw-timer" id="gw-timer-'+g.id+'">⏱ '+timeLeft+'</div>':'')+'<div class="gw-footer"><span class="gw-participants">'+((g.participants||[]).length)+' participants</span>'+enterBtn+'</div>'+winnerHtml+modHtml;list.appendChild(card)})}
function enterGiveaway(id){if(!userStorage.currentUser){showToast('Login to enter');return}var g=giveawayData.find(function(x){return x.id===id});if(!g||g.ended){showToast('Giveaway not available');return}if(!g.participants)g.participants=[];if(g.participants.includes(userStorage.currentUser)){showToast('Already entered');return}g.participants.push(userStorage.currentUser);saveGiveaways();renderGiveaways();showToast('Entered giveaway!')}
function endGiveaway(id){var g=giveawayData.find(function(x){return x.id===id});if(!g)return;if(!g.participants||!g.participants.length){showToast('No participants');return}var winner=g.participants[Math.floor(Math.random()*g.participants.length)];g.winner=winner;g.ended=true;saveGiveaways();renderGiveaways();sysMsg('🏆 Giveaway "'+g.title+'" has ended! Winner: '+winner+'! Congratulations!','announcements','normal');sysMsg('🏆 Giveaway "'+g.title+'" ended! Winner: '+winner+'!','global-chat','');showToast('Winner: '+winner+'!');renderCommunityAnnouncements()}
function deleteGiveaway(id){if(!confirm('Delete this giveaway?'))return;var i=giveawayData.findIndex(function(x){return x.id===id});if(i>-1){giveawayData.splice(i,1);saveGiveaways();renderGiveaways()}}
function openModModal(type){if(!isMod()){showToast('Moderator access required');return}var m=safeEl('mod-action-modal'),c=safeEl('mod-action-content');if(!m||!c)return;var html='';if(type==='update'){html='<h2 style="color:#f00;margin-top:0">Add Update</h2><div class="create-form"><input type="text" id="mod-update-title" placeholder="Title" maxlength="60"><input type="text" id="mod-update-version" value="'+statusData.version+'" placeholder="Version" maxlength="20"><textarea id="mod-update-desc" placeholder="Description" rows="4" maxlength="500" style="background:#111;border:1px solid rgba(255,0,0,0.3);color:#fff;padding:10px;border-radius:8px;resize:vertical;width:100%"></textarea><select id="mod-update-priority" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px"><option value="normal">Normal</option><option value="high">High Priority</option></select><input type="file" id="mod-update-image" accept="image/*" style="color:#ccc;background:transparent;border:none;padding:4px 0"><button onclick="submitModUpdate()">Publish Update</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='announcement'){html='<h2 style="color:#f00;margin-top:0">Create Announcement</h2><div class="create-form"><input type="text" id="mod-ann-title" placeholder="Title" maxlength="80"><textarea id="mod-ann-content" placeholder="Content" rows="4" maxlength="400" style="background:#111;border:1px solid rgba(255,0,0,0.3);color:#fff;padding:10px;border-radius:8px;resize:vertical;width:100%"></textarea><select id="mod-ann-type" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px"><option value="normal">Normal</option><option value="emergency">Emergency</option><option value="maintenance">Maintenance</option></select><button onclick="submitModAnnouncement()">Post Announcement</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='status'){html='<h2 style="color:#f00;margin-top:0">Game Status</h2><div class="create-form"><label style="color:#999;font-size:12px;text-align:left">Game Status</label><select id="mod-status-game" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px"><option value="online"'+(statusData.game==='online'?' selected':'')+'>Online</option><option value="offline"'+(statusData.game==='offline'?' selected':'')+'>Offline</option><option value="maintenance"'+(statusData.game==='maintenance'?' selected':'')+'>Maintenance</option></select><label style="color:#999;font-size:12px;text-align:left">Dev / Website Status</label><select id="mod-status-dev" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px"><option value="online"'+(statusData.dev==='online'?' selected':'')+'>Online</option><option value="offline"'+(statusData.dev==='offline'?' selected':'')+'>Offline</option></select><input type="text" id="mod-status-version" value="'+statusData.version+'" placeholder="Version number"><input type="text" id="mod-status-note" value="'+(statusData.note||'')+'" placeholder="Status note"><input type="text" id="mod-status-ann" value="'+(statusData.announcement||'')+'" placeholder="Active announcement (optional)"><button onclick="submitModStatus()">Update Status</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='faq'){html='<h2 style="color:#f00;margin-top:0">Add FAQ</h2><div class="create-form"><input type="text" id="mod-faq-q" placeholder="Question" maxlength="120"><textarea id="mod-faq-a" placeholder="Answer" rows="4" maxlength="400" style="background:#111;border:1px solid rgba(255,0,0,0.3);color:#fff;padding:10px;border-radius:8px;resize:vertical;width:100%"></textarea><button onclick="submitModFaq()">Add FAQ</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='giveaway'){html='<h2 style="color:#f00;margin-top:0">Create Giveaway</h2><div class="create-form"><input type="text" id="mod-gw-title" placeholder="Giveaway title" maxlength="80"><textarea id="mod-gw-desc" placeholder="Description" rows="3" maxlength="300" style="background:#111;border:1px solid rgba(255,0,0,0.3);color:#fff;padding:10px;border-radius:8px;resize:vertical;width:100%"></textarea><input type="text" id="mod-gw-reward" placeholder="Reward (e.g. Robux, Badge)" maxlength="100"><select id="mod-gw-duration" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px"><option value="3600000">1 Hour</option><option value="21600000">6 Hours</option><option value="86400000" selected>24 Hours</option><option value="259200000">3 Days</option><option value="604800000">7 Days</option></select><button onclick="submitModGiveaway()">Create Giveaway</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='emergency'){html='<h2 style="color:#f44;margin-top:0">⚠ Emergency Alert</h2><div class="create-form"><textarea id="mod-emerg-text" placeholder="Emergency message" rows="3" maxlength="300" style="background:#111;border:1px solid rgba(255,50,50,0.4);color:#fff;padding:10px;border-radius:8px;resize:vertical;width:100%"></textarea><button onclick="submitEmergency()" style="background:#b00">Broadcast Emergency</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='maintenance'){html='<h2 style="color:#fa0;margin-top:0">🔧 Maintenance Notice</h2><div class="create-form"><textarea id="mod-maint-text" placeholder="Maintenance message" rows="3" maxlength="300" style="background:#111;border:1px solid rgba(255,165,0,0.3);color:#fff;padding:10px;border-radius:8px;resize:vertical;width:100%"></textarea><button onclick="submitMaintenance()" style="background:#865200">Post Notice</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='clearchat'){html='<h2 style="color:#f00;margin-top:0">Clear Chat</h2><p style="color:#999;font-size:13px">Select channel to clear:</p><div class="create-form"><select id="mod-clear-ch" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px"><option value="global-chat">global-chat</option><option value="groups-lounge">groups-lounge</option><option value="voice-chat">voice-chat</option><option value="art-cosplay">art-cosplay</option><option value="announcements">announcements</option></select><button onclick="submitClearChat()" style="background:#900">Clear Channel</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='sysmsg'){html='<h2 style="color:#f00;margin-top:0">System Message</h2><div class="create-form"><select id="mod-sysmsg-ch" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px"><option value="global-chat">global-chat</option><option value="announcements">announcements</option><option value="art-cosplay">art-cosplay</option></select><textarea id="mod-sysmsg-text" placeholder="Message content" rows="3" maxlength="300" style="background:#111;border:1px solid rgba(255,0,0,0.3);color:#fff;padding:10px;border-radius:8px;resize:vertical;width:100%"></textarea><button onclick="submitSysMsg()">Send</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
else if(type==='deletegroup'){var groupKeys=Object.keys(communityData.groups);var opts=groupKeys.length?groupKeys.map(function(k){return'<option value="'+k+'">'+k+'</option>'}).join(''):'<option value="">No groups exist</option>';html='<h2 style="color:#f00;margin-top:0">Delete Group</h2><div class="create-form"><select id="mod-del-group" style="background:#111;border:1px solid rgba(255,255,255,0.15);color:#fff;padding:10px;border-radius:8px">'+opts+'</select><button onclick="submitDeleteGroup()" style="background:#900">Delete Group</button><button onclick="closeModModal()" class="cancel-btn">Cancel</button></div>'}
c.innerHTML=html;m.classList.remove('hidden')}
function closeModModal(){var m=safeEl('mod-action-modal');if(m)m.classList.add('hidden')}
function submitModUpdate(){verifyMod(function(){var t=safeEl('mod-update-title'),v=safeEl('mod-update-version'),d=safeEl('mod-update-desc'),p=safeEl('mod-update-priority'),img=safeEl('mod-update-image');if(!t||!v||!d||!t.value.trim()||!v.value.trim()||!d.value.trim()){alert('Fill all required fields');return}var entry={id:Date.now(),title:t.value.trim(),version:v.value.trim().replace(/^v/,''),description:d.value.trim(),priority:p?p.value:'normal',author:userStorage.currentUser,timestamp:Date.now(),image:null};if(img&&img.files.length>0){var reader=new FileReader();reader.onload=function(e){entry.image=e.target.result;updatesData.unshift(entry);saveUpdates();closeModModal();showToast('Update published!');renderUpdates()};reader.readAsDataURL(img.files[0])}else{updatesData.unshift(entry);saveUpdates();closeModModal();showToast('Update published!');renderUpdates()}})}
function submitModAnnouncement(){verifyMod(function(){var ti=safeEl('mod-ann-title'),co=safeEl('mod-ann-content'),ty=safeEl('mod-ann-type');if(!ti||!co||!ty||!ti.value.trim()||!co.value.trim()){alert('Fill all fields');return}sysMsg('['+ty.value.toUpperCase()+'] '+ti.value.trim()+': '+co.value.trim(),'announcements',ty.value);closeModModal();showToast('Announcement posted!');renderCommunityAnnouncements()})}
function submitModStatus(){verifyMod(function(){var g=safeEl('mod-status-game'),d=safeEl('mod-status-dev'),v=safeEl('mod-status-version'),n=safeEl('mod-status-note'),a=safeEl('mod-status-ann');if(g)statusData.game=g.value;if(d)statusData.dev=d.value;if(v&&v.value.trim())statusData.version=v.value.trim().replace(/^v/,'');if(n)statusData.note=n.value;if(a)statusData.announcement=a.value;statusData.timestamp=Date.now();saveStatus();closeModModal();showToast('Status updated!');renderStatusCard();updateVersionDisplay()})}
function submitModFaq(){verifyMod(function(){var q=safeEl('mod-faq-q'),a=safeEl('mod-faq-a');if(!q||!a||!q.value.trim()||!a.value.trim()){alert('Fill all fields');return}faqData.push({id:Date.now(),question:q.value.trim(),answer:a.value.trim()});saveFaqs();closeModModal();showToast('FAQ added!');renderFaqs()})}
function submitModGiveaway(){verifyMod(function(){var ti=safeEl('mod-gw-title'),de=safeEl('mod-gw-desc'),re=safeEl('mod-gw-reward'),du=safeEl('mod-gw-duration');if(!ti||!de||!re||!du||!ti.value.trim()||!re.value.trim()){alert('Fill all fields');return}var dur=parseInt(du.value);var gw={id:Date.now(),title:ti.value.trim(),description:de.value.trim(),reward:re.value.trim(),endsAt:Date.now()+dur,ended:false,winner:null,participants:[],createdBy:userStorage.currentUser,timestamp:Date.now()};giveawayData.push(gw);saveGiveaways();sysMsg('🎁 NEW GIVEAWAY: "'+gw.title+'" — Prize: '+gw.reward+' · Click Giveaway tab to enter!','announcements','normal');sysMsg('🎁 NEW GIVEAWAY: "'+gw.title+'"','global-chat','');closeModModal();showToast('Giveaway created!');renderGiveaways();renderCommunityAnnouncements()})}
function submitEmergency(){verifyMod(function(){var t=safeEl('mod-emerg-text');if(!t||!t.value.trim()){alert('Enter message');return}sysMsg('⚠️ EMERGENCY: '+t.value.trim(),'announcements','emergency');sysMsg('⚠️ EMERGENCY: '+t.value.trim(),'global-chat','emergency');statusData.announcement='⚠️ '+t.value.trim();saveStatus();closeModModal();showToast('Emergency alert broadcast!');renderStatusCard()})}
function submitMaintenance(){verifyMod(function(){var t=safeEl('mod-maint-text');if(!t||!t.value.trim()){alert('Enter message');return}sysMsg('🔧 MAINTENANCE: '+t.value.trim(),'announcements','maintenance');sysMsg('🔧 MAINTENANCE: '+t.value.trim(),'global-chat','maintenance');statusData.game='maintenance';statusData.announcement='🔧 '+t.value.trim();saveStatus();closeModModal();showToast('Maintenance notice posted!');renderStatusCard()})}
function submitClearChat(){verifyMod(function(){var ch=safeEl('mod-clear-ch');if(!ch)return;var name=ch.value;communityData.channels[name]=[];if(fbReady){db.ref('channels/'+name).remove()}else{saveCommunityData()}var clrMsg=buildSysMsg('Chat cleared by a moderator.','');if(!communityData.channels[name])communityData.channels[name]=[];communityData.channels[name].push(clrMsg);if(fbReady){db.ref('channels/'+name).push(clrMsg)}else{saveCommunityData()}closeModModal();showToast('Chat cleared!');if(communityState.currentChannel===name){renderCommunityMessages();renderChannelMeta();var c2=safeEl('community-messages');if(c2)c2.scrollTop=c2.scrollHeight}})}
function submitSysMsg(){verifyMod(function(){var ch=safeEl('mod-sysmsg-ch'),tx=safeEl('mod-sysmsg-text');if(!ch||!tx||!tx.value.trim()){alert('Enter message');return}var sysCh=ch.value;var sysText='📢 '+tx.value.trim();if(!communityData.channels[sysCh])communityData.channels[sysCh]=[];var sysM=buildSysMsg(sysText,'');communityData.channels[sysCh].push(sysM);if(fbReady){db.ref('channels/'+sysCh).push(sysM)}else{saveCommunityData()}closeModModal();showToast('System message sent!');if(communityState.currentChannel===sysCh){renderCommunityMessages();renderChannelMeta();var c2=safeEl('community-messages');if(c2)c2.scrollTop=c2.scrollHeight}})}
