function renderCommunityChannelTitle(){var ti=safeEl('community-channel-title'),to=safeEl('community-channel-topic');if(!ti||!to)return;var ch=communityState.currentChannel;var map={'global-chat':['global-chat','Survival horror community conversation.'],'groups-lounge':communityState.currentGroup?['group: '+communityState.currentGroup,'Group private chat.']:['groups-lounge','Create or join a group.'],'voice-chat':['voice-chat','Simulated voice presence.'],'art-cosplay':['art-cosplay','Share images and media.'],'announcements':['announcements','Official moderator announcements.']};var pair=map[ch]||[ch,''];ti.textContent=pair[0];to.textContent=pair[1]}
function renderChannelMeta(){var m=safeEl('community-channel-meta');if(!m)return;var ch=communityState.currentChannel;if(ch==='groups-lounge'&&communityState.currentGroup){var g=communityData.groups[communityState.currentGroup];m.textContent=(g&&g.members?g.members.length:0)+' members'}else if(ch==='voice-chat'){m.textContent=communityState.voiceJoined?'✓ Connected':'Disconnected'}else{var chMsgs=(ch==='groups-lounge'&&communityState.currentGroup&&communityData.groups[communityState.currentGroup])?(communityData.groups[communityState.currentGroup].messages||[]):(communityData.channels[ch]||[]);m.textContent=chMsgs.length+' messages'}}
function getCurrentChannelMessages(){if(communityState.currentChannel==='groups-lounge'){if(communityState.currentGroup&&communityData.groups[communityState.currentGroup])return(communityData.groups[communityState.currentGroup].messages||[]);return[]}return communityData.channels[communityState.currentChannel]||[]}
function renderCommunityMessages(){var c=safeEl('community-messages');if(!c)return;c.innerHTML='';var msgs=getCurrentChannelMessages().slice().sort(function(a,b){return Number(a.id)-Number(b.id)});if(communityState.currentChannel==='groups-lounge'&&!communityState.currentGroup){c.innerHTML='<div class="sys-msg">Select or create a group to start chatting.</div>';return}if(!msgs.length){c.innerHTML='<div class="sys-msg">No messages yet. Say something!</div>';return}msgs.forEach(function(msg){if(!msg||!msg.id)return;var isSystem=msg.author==='SYSTEM'||msg.author==='naughtygoat'||msg.role==='system';var el=document.createElement('div');el.className='comm-message'+(msg.deleted?' deleted':'')+(isSystem?' sys-message':'');var statusCls=isSystem?'status-offline':(onlineUsers[msg.author]==='online'?'status-online':onlineUsers[msg.author]==='idle'?'status-idle':'status-offline');var role=msg.role||'user';var rLabel=role==='moderator'?'MOD':role==='admin'?'ADMIN':role==='guest'?'GUEST':role==='system'?'SYS':'USER';var canAct=!msg.deleted&&!isSystem&&(msg.author===userStorage.currentUser||isMod());var actHtml=canAct?'<button onclick="editCommunityMessage(\''+msg.id+'\')">Edit</button><button onclick="deleteCommunityMessage(\''+msg.id+'\')">Delete</button><button onclick="copyCommunityMessage(\''+msg.id+'\')">Copy</button>':'';var replHtml='';if(msg.replies&&msg.replies.length)replHtml='<div class="replies-group">'+msg.replies.map(function(r){return'<div class="reply-bubble"><span class="reply-author">'+getDisplayNameForUser(r.author)+'</span><span class="reply-text">'+r.text+'</span><span class="reply-time">'+renderTimestamp(r.timestamp)+'</span></div>'}).join('')+'</div>';var attHtml='';if(msg.attachments&&msg.attachments.length)attHtml=msg.attachments.map(function(a){return a.kind==='image'?'<img src="'+a.data+'" class="msg-img" alt="">':'<a href="'+a.data+'" target="_blank" class="msg-file">📎 '+a.name+'</a>'}).join('');var rxHtml=communityEmojis.map(function(em){var cnt=msg.reactions&&msg.reactions[em]?msg.reactions[em].length:0;var active=msg.reactions&&msg.reactions[em]&&userStorage.currentUser&&msg.reactions[em].includes(userStorage.currentUser);return'<button class="comm-reaction'+(active?' reacted':'')+'" onclick="toggleCommunityReaction(\''+msg.id+'\',\''+em+'\')">'+em+(cnt?' <span class="rx-count">'+cnt+'</span>':'')+'</button>'}).join('');var displayName=isSystem?'naughtygoat':getDisplayNameForUser(msg.author);var avatarChar=isSystem?'N':getAvatarChar(displayName);var avatarStyle=isSystem?'background:linear-gradient(135deg,#8b0000,#cc0000);border-color:#f00':'';el.innerHTML='<div class="comm-avatar" style="'+avatarStyle+'"><span class="status-dot '+statusCls+'"></span>'+avatarChar+'</div><div class="comm-message-body"><div class="comm-msg-header"><strong class="msg-author">'+displayName+'</strong><span class="comm-role-badge badge-'+role+'">'+rLabel+'</span><span class="msg-time">'+renderTimestamp(msg.timestamp)+(msg.edited&&!msg.deleted?' <em>(edited)</em>':'')+'</span></div><div class="comm-message-text'+(msg.deleted?' deleted-text':'')+(msg.annType==='emergency'?' emergency-text':msg.annType==='maintenance'?' maint-text':'')+'">'+( msg.deleted?'Message deleted':msg.text)+'</div>'+attHtml+replHtml+'<div class="comm-message-actions">'+(msg.deleted||isSystem?'':'<button onclick="replyToCommunityMessage(\''+msg.id+'\')">Reply</button>')+actHtml+'</div><div class="comm-reactions">'+rxHtml+'</div></div>';c.appendChild(el)});c.scrollTop=c.scrollHeight}
function handleChatKey(e){if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendCommunityMessage()}}
function sendCommunityMessage(){var inp=safeEl('community-message-input');if(!inp)return;var text=inp.value.trim();if(!userStorage.currentUser){alert('Please login or continue as guest');return}if(!currentUid){showToast('Connecting to server, please wait...');return}if(isUserMuted(userStorage.currentUser)){showToast('You are muted for '+getMuteSecondsLeft(userStorage.currentUser)+'s');checkMyMuteStatus();return}if(!text&&!communityState.pendingAttachments.length)return;if(communityState.currentChannel==='groups-lounge'&&!communityState.currentGroup){alert('Select a group first');return}if(communityState.currentChannel==='announcements'&&!isMod()){showToast('Only moderators can post in announcements');return}if(communityState.currentChannel==='voice-chat'){showToast('Voice chat is listen-only');return}var attachments=communityState.pendingAttachments.map(function(a){return{name:a.name,type:a.type,kind:a.kind,data:a.data}});var msg=buildMsg(text,attachments);if(communityState.currentChannel==='groups-lounge'){if(!communityData.groups[communityState.currentGroup])return;if(!communityData.groups[communityState.currentGroup].messages)communityData.groups[communityState.currentGroup].messages=[];if(fbReady){db.ref('groups/'+communityState.currentGroup+'/messages').push(msg);db.ref('groups/'+communityState.currentGroup+'/lastActivity').set(Date.now())}communityData.groups[communityState.currentGroup].messages.push(msg);communityData.groups[communityState.currentGroup].lastActivity=Date.now();if(!fbReady)saveCommunityData()}else{if(!communityData.channels[communityState.currentChannel])communityData.channels[communityState.currentChannel]=[];communityData.channels[communityState.currentChannel].push(msg);if(fbReady){db.ref('channels/'+communityState.currentChannel).push(msg)}else{saveCommunityData()}}inp.value='';communityState.pendingAttachments=[];delete communityState.typingUsers[userStorage.currentUser];renderTypingIndicator();var fi=safeEl('community-file-input');if(fi)fi.value='';renderCommunityAttachmentPreview();renderCommunityMessages();renderChannelMeta();var c2=safeEl('community-messages');if(c2)c2.scrollTop=c2.scrollHeight}
function handleCommunityAttachment(e){var files=Array.from(e.target.files||[]);communityState.pendingAttachments=[];files.forEach(function(f){var item={name:f.name,type:f.type,kind:f.type.startsWith('image/')?'image':'file',data:null};if(item.kind==='image'){var r=new FileReader();r.onload=function(ev){item.data=ev.target.result;renderCommunityAttachmentPreview()};r.readAsDataURL(f)}communityState.pendingAttachments.push(item)});renderCommunityAttachmentPreview()}
function renderCommunityAttachmentPreview(){var p=safeEl('community-attachment-preview');if(!p)return;p.innerHTML='';communityState.pendingAttachments.forEach(function(item,i){var el=document.createElement('div');el.className='preview-item';el.innerHTML=(item.kind==='image'&&item.data?'<img src="'+item.data+'" alt="">':'<span>📄</span>')+'<span>'+item.name+'</span><button onclick="removeCommunityAttachment('+i+')">&#x2715;</button>';p.appendChild(el)})}
