function editCommunityMessage(id){var msg=findMessageById(id);if(!msg||msg.deleted)return;if(msg.author!==userStorage.currentUser){if(!isMod())return;if(!currentUid)return;}var u=prompt('Edit message:',msg.text);if(u!==null&&u.trim()){msg.text=u.trim();msg.edited=true;if(fbReady){fbUpdateMsg(msg.id,{text:msg.text,edited:true})}else{saveCommunityData();renderCommunityMessages()}}}
function deleteCommunityMessage(id){var msg=findMessageById(id);if(!msg)return;if(msg.author!==userStorage.currentUser){if(!isMod())return;if(!currentUid)return;}msg.deleted=true;if(fbReady){fbUpdateMsg(msg.id,{deleted:true})}else{saveCommunityData();renderCommunityMessages()}}
