function toggleCommunityReaction(id,emoji){if(!userStorage.currentUser){showToast('Login to react');return}var msg=findMessageById(id);if(!msg||msg.deleted)return;msg.reactions=msg.reactions||{};msg.reactions[emoji]=msg.reactions[emoji]||[];var i=msg.reactions[emoji].indexOf(userStorage.currentUser);if(i>-1)msg.reactions[emoji].splice(i,1);else msg.reactions[emoji].push(userStorage.currentUser);if(fbReady){fbUpdateMsg(msg.id,{reactions:msg.reactions})}else{saveCommunityData();renderCommunityMessages()}}
