function renderVoiceStatus(){var v=safeEl('community-voice-status'),ul=safeEl('voice-users-list');if(v)v.textContent=communityState.voiceJoined?'✓ Connected to Voice':'Disconnected';if(ul){if(communityState.voiceUsers.length){ul.innerHTML=communityState.voiceUsers.map(function(u){return'<div style="display:flex;align-items:center;gap:5px;padding:2px 0"><span class="status-dot status-online" style="position:static;width:7px;height:7px;flex-shrink:0"></span><span>'+u+'</span></div>'}).join('')}else{ul.innerHTML=''}}}
function toggleVoiceChannel(){if(getUserRole()==='guest'){showToast('Create an account to join voice');return}communityState.voiceJoined=!communityState.voiceJoined;if(communityState.voiceJoined){if(userStorage.currentUser&&!communityState.voiceUsers.includes(userStorage.currentUser))communityState.voiceUsers.push(userStorage.currentUser)}else{communityState.voiceUsers=communityState.voiceUsers.filter(function(u){return u!==userStorage.currentUser})}sysMsg((userStorage.currentUser||'Guest')+(communityState.voiceJoined?' joined':' left')+' voice chat.','voice-chat','');renderCommunity()}
function createCommunityGroup(){var ne=safeEl('community-group-name');if(!ne)return;var name=sanitizeGroupName(ne.value.trim());if(!name){alert('Invalid or offensive group name');return}if(!userStorage.currentUser){alert('Login first');return}var groupData={leader:userStorage.currentUser,created:Date.now(),lastActivity:Date.now(),members:[{username:userStorage.currentUser,status:'online'}],messages:[]};if(fbReady){db.ref('groups/'+name).once('value',function(snap){if(snap.exists()){alert('Group already exists');return}db.ref('groups/'+name).set(groupData)})}else{if(communityData.groups[name]){alert('Group already exists');return}communityData.groups[name]=groupData;saveCommunityData()}communityState.currentChannel='groups-lounge';communityState.currentGroup=name;ne.value='';selectCommunityGroup(name);renderCommunity()}
