function selectCommunityGroup(name){if(!communityData.groups[name])return;communityState.currentChannel='groups-lounge';communityState.currentGroup=name;if(userStorage.currentUser&&fbReady){db.ref('groups/'+name+'/members').once('value',function(snap){var members=snap.val()||[];if(!Array.isArray(members))members=Object.values(members);if(!members.find(function(m){return m&&m.username===userStorage.currentUser})){members.push({username:userStorage.currentUser,status:'online'});db.ref('groups/'+name+'/members').set(members);db.ref('groups/'+name+'/lastActivity').set(Date.now())}})}if(fbReady){db.ref('groups/'+name+'/messages').on('value',function(snap){var raw=snap.val()||{};var msgs=[];Object.keys(raw).forEach(function(k){var s=sanitizeMsg(raw[k]);if(s)msgs.push(s)});msgs.sort(function(a,b){return Number(a.id)-Number(b.id)});if(!communityData.groups[name])communityData.groups[name]={};communityData.groups[name].messages=msgs;renderCommunityMessages()})}else{renderCommunity()}}
function checkGroupInactivity(){Object.keys(communityData.groups).forEach(function(name){var g=communityData.groups[name];if(!g||!g.lastActivity)return;if(Date.now()-g.lastActivity>600000){if(communityState.currentGroup===name){communityState.currentGroup=null;communityState.currentChannel='groups-lounge'}if(fbReady){db.ref('groups/'+name).remove()}else{delete communityData.groups[name];saveCommunityData()}renderCommunity()}})}
function checkGiveawayExpiry(){var changed=false;giveawayData.forEach(function(g){if(!g.ended&&g.endsAt&&Date.now()>g.endsAt){if(g.participants&&g.participants.length){g.winner=g.participants[Math.floor(Math.random()*g.participants.length)];sysMsg('🏆 Giveaway "'+g.title+'" ended! Winner: '+g.winner+'!','announcements','normal')}g.ended=true;changed=true}});if(changed){saveGiveaways();renderGiveaways();if(communityState.currentChannel==='announcements'||communityState.currentChannel==='global-chat')renderCommunity();renderCommunityAnnouncements()}}
function renderCommunityGroupList(){var l=safeEl('community-group-list');if(!l)return;l.innerHTML='';var keys=Object.keys(communityData.groups);if(!keys.length){l.innerHTML='<div style="color:#666;font-size:12px;padding:6px 0">No groups yet</div>';return}keys.forEach(function(name){var g=communityData.groups[name];var el=document.createElement('div');el.className='comm-group-item';el.innerHTML='<div><strong>'+name+'</strong><small>'+(g.members?g.members.length:0)+' member'+((g.members&&g.members.length===1)?'':'s')+'</small></div><button onclick="selectCommunityGroup(\''+name+'\')">Open</button>';l.appendChild(el)})}
function renderCommunityMemberList(){var l=safeEl('community-member-list');if(!l)return;l.innerHTML='';var members=[];if(communityState.currentChannel==='groups-lounge'&&communityState.currentGroup&&communityData.groups[communityState.currentGroup]){(communityData.groups[communityState.currentGroup].members||[]).forEach(function(m){members.push(m.username)})}else{Object.keys(systemData.userRoles).forEach(function(u){members.push(u)});Object.keys(onlineUsers).forEach(function(u){if(members.indexOf(u)===-1)members.push(u)});if(userStorage.currentUser&&members.indexOf(userStorage.currentUser)===-1)members.push(userStorage.currentUser)}var onlineOnly=members.filter(function(u){return onlineUsers[u]==='online'||onlineUsers[u]==='idle'});if(!onlineOnly.length){l.innerHTML='<div style="color:#555;font-size:12px;padding:6px 0">No one online</div>';return}onlineOnly.sort();onlineOnly.forEach(function(u){var st=onlineUsers[u]||'offline';var r=systemData.userRoles[u]||'user';var el=document.createElement('div');el.className='community-member';el.innerHTML='<div style="display:flex;align-items:center;gap:6px"><span class="status-dot status-'+st+'" style="position:static;flex-shrink:0"></span><span class="member-name">'+u+'</span>'+(r==='moderator'?'<span class="member-role-badge mod-badge">MOD</span>':r==='guest'?'<span class="member-role-badge guest-badge">GUEST</span>':'')+'</div><span class="member-status-text '+st+'">'+st+'</span>';l.appendChild(el)})}
function renderCommunityAnnouncements(){var l=safeEl('community-announcements');if(!l)return;l.innerHTML='';var anns=(communityData.channels['announcements']||[]).filter(function(m){return m&&!m.deleted}).slice(-6).reverse();if(!anns.length){l.innerHTML='<div style="color:#555;font-size:12px;padding:6px 0">No announcements</div>';return}anns.forEach(function(msg){var el=document.createElement('div');var type=msg.annType||'normal';el.className='community-announcement ann-'+type;var delBtn=isMod()?'<button onclick="deleteAnnouncementSidebar(\'+msg.id+\'\')" style="background:none;border:none;color:#f44;font-size:10px;cursor:pointer;padding:2px 4px;float:right;text-shadow:none;line-height:1" title="Delete">✕</button>':'';el.innerHTML=delBtn+'<div class="ann-text">'+msg.text+'</div><time>'+renderTimestamp(msg.timestamp)+'</time>';l.appendChild(el)})}

